#include <iostream>
#include <algorithm>
using namespace std;
struct bingren
{
    string name;
    double temp;
    bool caugh;
};
int main()
{
    int n,count=0;
    cin>>n;
    bingren a[205];
    for(int i=0;i<=n-1;i++)
    {
        cin>>a[i].name>>a[i].temp>>a[i].caugh;
    }
    for(int i=0;i<=n-1;i++)
    {
        if(a[i].temp>=37.5&&a[i].caugh==1)
        {
            cout<<a[i].name<<endl;
            count++;
        }
    }
    cout<<count;
    return 0;
}
